var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 메인 드라이브에 치명적인 손상.</color>","JPN":"<color=#ff3636>警告。メインドライブに致命的な損傷。</color>","ENG":"<color=#ff3636>Warning. Critical damage to the main drive.</color>","TWN":"<color=#ff3636>警告。主引擎遭到致命損壞。</color>"},"stage":{"bg":"YAKSHA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 범인류 이민선 시무르그 출력 저하 64%</color>","JPN":"<color=#ff3636>警告。汎人類移民船シムルグ出力低下64％。</color>","ENG":"<color=#ff3636>Warning. Exodus Fleet of Humankind Simurgh Output decreased to 64%.</color>","TWN":"<color=#ff3636>警告。人類移民船西摩格輸出下降64%</color>"},"stage":{"bg":"YAKSHA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 범인류 이민선 시무르그 지구 대기권에 돌입합니다. </color>","JPN":"<color=#ff3636>警告。汎人類移民船シムルグ、地球大気圏に突入します。</color>","ENG":"<color=#ff3636>Warning. Exodus Fleet of Humankind Simurgh entering Earth's atmosphere.</color>","TWN":"<color=#ff3636>警告。人類移民船西摩格進入地球大氣層。</color>"},"stage":{"bg":"YAKSHA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 표면 온도 급상승. 이민선 프레임에 심각한 손상 감지.</color>","JPN":"<color=#ff3636>警告。表面温度急上昇。移民船フレームに深刻な損傷感知。</color>","ENG":"<color=#ff3636>Warning. Surface temperature rapidly increasing. Detecting severe damage to Exodus Fleet's frame.</color>","TWN":"<color=#ff3636>警告。表面溫度迅速升高。檢測到移民船軀殼嚴重損壞。</color>"},"stage":{"bg":"YAKSHA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 경고. 경고. 경고. 경고────────────!</color>","JPN":"<color=#ff3636>警告。警告。警告。警告。警告────────────！</color>","ENG":"<color=#ff3636>Warning. Warning. Warning. Warning. Warning!!</color>","TWN":"<color=#ff3636>警告。警告。警告。警告。警告────────────！</color>"},"stage":{"bg":"YAKSHA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>이민선 시무르그. 보조 동력으로 전환. 항행 목표를 변경합니다.</color>","JPN":"<color=#ff3636>移民船シムルグ。補助動力に転換。航行目標を変更します。</color>","ENG":"<color=#ff3636>Exodus Fleet Simurgh. Switching to backup power. Changing navigation objective.</color>","TWN":"<color=#ff3636>移民船西摩格切換至輔助動力。即將更改航行目標。</color>"},"stage":{"bg":"YAKSHA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"메이즈 전대장님! 우주로부터 통신이 잡혔습니다!","JPN":"メイズ戦隊長！　宇宙から通信を捉えました！","ENG":"Maze Commander! We're picking up a transmission from space!","TWN":"梅茲戰隊長！我們收到了來自太空的通訊！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스인가! 당장 연결해!","JPN":"アリスか！　今すぐ繋げろ！","ENG":"Is it Alice?! Connect me immediately!","TWN":"是艾莉絲！立即連接！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"지휘부에! 앨리스다!","JPN":"司令部！　アリスだ！","ENG":"Headquarters! This is Alice!","TWN":"指揮部！我是艾莉絲！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스 전대장! 자네 괜찮은가!!","JPN":"アリス戦隊長！　君、大丈夫なのか！！","ENG":"Commander Alice!! Are you all right?!","TWN":"艾莉絲戰隊長！你還好嗎！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"들리나! 아무나 대답해!","JPN":"聞こえるか！　誰でもいいから返事をしろ！","ENG":"Do you hear me?! Can anyone say something?!","TWN":"能聽得到嗎？請回答！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"녀석의 동력원은 파괴했어! 이면세계로 도주하기 전에 어떻게든 막아야 돼!","JPN":"やつの動力源は破壊した！　裏世界に逃走する前に、なんとかして止めないと！","ENG":"Her power source is destroyed! We have to stop her before she retreats to the Counterside!","TWN":"我已經摧毀了它的動力源！在它撤回異界之前，一定要阻止它！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"녀석은 사도……","JPN":"やつは使徒……","ENG":"She's an Apostle–","TWN":"那傢伙是使徒……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……죽게 될거야. 그러니까!","JPN":"……死ぬことになる。だから！","ENG":"–are going to die!","TWN":"……會死的。所以！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"우주 잔류 침식파 때문인가, 수신 감도가 좋지 않아.","JPN":"宇宙残留侵食波のせいか、受信感度がよくない。","ENG":"Is it because of the Corruption rays remaining in space? The signal's weak.","TWN":"喂？可能是因為空間殘留的侵蝕波，接收靈敏度不好！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지휘부다! 당장 복귀해, 전대장! 혼자 달려들어서 뭘 어떻게 하려고!","JPN":"司令部からの指示だ！　直ちに復帰しろ、戦隊長！　一人で飛び込んでどうするつもりだ！","ENG":"This is Headquarters! Return to base immediately, Commander! Rushing in there alone won't achieve anything!","TWN":"這裡是指揮部！馬上返航，戰隊長！你自己一個人能幹什麼！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"구조선을 보내겠다 그러니까……!","JPN":"救助船を送る。だから……！","ENG":"I'm sending a rescue ship, so...!","TWN":"我會派出救援艦船，所以……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……차원 도약 직전에 궤도를 틀어버리면 돼!","JPN":"……次元跳躍の直前に軌道を曲げさせればいい！","ENG":"–change the trajectory right before the dimension jump!","TWN":"……在次元躍遷前改變軌道就可以……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 소리 하는 거야! 적 함선이 차원 도약을 하고 있다는 뜻인가!","JPN":"何を言っている！　敵の艦船が次元跳躍しているということか？","ENG":"What are you talking about?! Is the enemy ship getting ready to make a dimension jump?!","TWN":"你在說什麼！你是說敵人的艦船正在進行次元躍遷嗎！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……기동 전이라면 분명 타격을 가할 수 있어!","JPN":"……起動前ならきっとダメージを与えられる！","ENG":"–I know that thing will take damage if I strike before it activates!","TWN":"……如果搶在啟動之前，一定能造成傷害！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"거기에 휘말린 자네는! 단거리 공간 도약으로는 벗어날 수 없어 죽는다고!","JPN":"それに巻き込まれる君はどうなる！　短距離空間跳躍では抜け出せない！　死ぬぞ！","ENG":"But what if you get caught up in it? You won't get away with just a short-distance space jump! You'll get yourself killed!","TWN":"但你也會被捲入的！用近距空間跳耀沒辦法逃出來！會沒命的！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"앨리스! 앨리스 전대장!!","JPN":"アリス！　アリス戦隊長！！","ENG":"Alice?! Commander Alice!!","TWN":"艾莉絲！艾莉絲戰隊長！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"들리나!","JPN":"聞こえるか！","ENG":"Do you hear me?!","TWN":"聽得見嗎！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};